# Module providing functional utilities and higher-order functions
# Cross-module use of shapes

from shapes import IShape, Circle, Rectangle

class ShapeCalculator:
    shapes: list[IShape]

    def __init__(self):
        self.shapes = []

    def add_shape(self, shape: IShape) -> None:
        self.shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total = total + shape.area()
        return total

    def total_perimeter(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total = total + shape.perimeter()
        return total

# Function with callback type parameter
def for_each_shape(calculator: ShapeCalculator, action: (IShape) -> None) -> None:
    for shape in calculator.shapes:
        action(shape)

def create_test_shapes() -> list[IShape]:
    result: list[IShape] = []
    result.append(Circle(5.0))
    result.append(Rectangle(3.0, 4.0))
    result.append(Circle(2.0))
    return result
